module top_module(
    Q      ,
    obf_CLK    ,
    RESET_B
);output reg [3:0] Q;
    input  obf_CLK;
    input  RESET_B;

    always @(posedge obf_CLK) begin
        if (RESET_B == 0) begin
            Q <= 4'b0000;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
